// EncryptionKeyManager.java
package com.app.security;

import android.content.Context;
import android.security.keystore.KeyGenParameterSpec;
import android.security.keystore.KeyProperties;
import android.util.Base64;

import java.security.KeyStore;

import javax.crypto.KeyGenerator;
import javax.crypto.SecretKey;

/**
 * Manages encryption keys using Android Keystore system.
 * Keys are hardware-backed when available and never leave the secure element.
 */
public class EncryptionKeyManager {

    private static final String ANDROID_KEYSTORE = "AndroidKeyStore";
    private static final String KEY_ALIAS_USER_PROFILE = "user_profile_key";
    private static final String KEY_ALIAS_PAYMENT_INFO = "payment_info_key";
    private static final String KEY_ALIAS_SESSION_DATA = "session_data_key";

    private final KeyStore keyStore;

    public EncryptionKeyManager() throws Exception {
        keyStore = KeyStore.getInstance(ANDROID_KEYSTORE);
        keyStore.load(null);
    }

    public SecretKey getOrCreateKey(String alias) throws Exception {
        if (keyStore.containsAlias(alias)) {
            KeyStore.SecretKeyEntry entry = (KeyStore.SecretKeyEntry) keyStore.getEntry(alias, null);
            return entry.getSecretKey();
        }
        return generateKey(alias);
    }

    private SecretKey generateKey(String alias) throws Exception {
        KeyGenerator keyGenerator = KeyGenerator.getInstance(
                KeyProperties.KEY_ALGORITHM_AES, ANDROID_KEYSTORE);

        KeyGenParameterSpec spec = new KeyGenParameterSpec.Builder(
                alias,
                KeyProperties.PURPOSE_ENCRYPT | KeyProperties.PURPOSE_DECRYPT)
                .setBlockModes(KeyProperties.BLOCK_MODE_GCM)
                .setEncryptionPaddings(KeyProperties.ENCRYPTION_PADDING_NONE)
                .setKeySize(256)
                .setRandomizedEncryptionRequired(true)
                .setUserAuthenticationRequired(false) // Set true if biometric gate desired
                .build();

        keyGenerator.init(spec);
        return keyGenerator.generateKey();
    }

    public SecretKey getUserProfileKey() throws Exception {
        return getOrCreateKey(KEY_ALIAS_USER_PROFILE);
    }

    public SecretKey getPaymentInfoKey() throws Exception {
        return getOrCreateKey(KEY_ALIAS_PAYMENT_INFO);
    }

    public SecretKey getSessionDataKey() throws Exception {
        return getOrCreateKey(KEY_ALIAS_SESSION_DATA);
    }

    public void deleteKey(String alias) throws Exception {
        if (keyStore.containsAlias(alias)) {
            keyStore.deleteEntry(alias);
        }
    }

    public void deleteAllKeys() throws Exception {
        deleteKey(KEY_ALIAS_USER_PROFILE);
        deleteKey(KEY_ALIAS_PAYMENT_INFO);
        deleteKey(KEY_ALIAS_SESSION_DATA);
    }
}